import { Link } from "react-router-dom";
import StatusDetails from "../../utils/StatusDetails";
import StatusDrop from "../../utils/StatusDrop";
import { v4 as uuidv4 } from 'uuid';
import { epochTogmt } from "../../utils/Common";
import authService from "src/auth/auth.service";

export const tableTriviaConstant = (fetchTriviaList, handleConfirmModal) => {
    return [
        {
            id: 1,
            name: "Title",
            cell: (row) => {
                return (
                    <Link to={`/trivia/edit/${row?.id}`}>
                        <span className="sub">{row.title}</span>
                    </Link>
                );
            },
            sortable: true,
            reorder: true,
            grow: 2,
            style: {
                color: "#202124",
                fontSize: "14px",
                fontWeight: 500,
            },
        },
        {
            id: 2,
            name: "Category",
            selector: (row) => row.category
        },
        {
            id: 3,
            name: "Views",
            selector: (row) => "-"
        },
        {
            id: 4,
            name: "Read",
            selector: (row) => "-"
        },
        {
            id: 5,
            name: "Reading average time",
            selector: (row) => "-"
        },
        {
            id: 6,
            name: "Action",
            cell: (row) => {
                return (
                    <StatusDrop
                        id={row.id}
                        status={row.status}
                        type={'TRIVIA'}
                        action={fetchTriviaList}
                        key={uuidv4()}
                        publishPermission={"TRIVIA_PUBLISH"}
                    />
                );
            },
            sortable: true,
            reorder: true,
        },
        {
            id: 7,
            name: "Date",
            selector: (row) => epochTogmt(row.createTime)
        },
        {
            id: 8,
            name: "Status",
            cell: (row) => {
                return (
                    <StatusDetails status={row.status} key={uuidv4()} />
                );
            },
            sortable: true,
            reorder: true,
        },
        {
            id: 9,
            name: "Delete",
            cell: (row) => {
                return <i className={"fa-regular fa-trash-can" + (row.status === "ENABLE" || !authService.getPermission("DELETE") ? " disable" : "")} onClick={(e) => { handleConfirmModal(row.id) }}></i>;
            },
            sortable: true,
            reorder: true,
        },
    ];
};
